/***************************************************************************
 *  KWS-DNN inference port from ML-KWS-for-MCU/Deployment/Source/NN/DNN    *
 *  (arm_fully_connected_q7 / arm_relu_q7 / arm_softmax_q7 -> libnn)       *
 ***************************************************************************/

#include <stdint.h>
#include <stdio.h>
#include "internal_nn_math.h"
#include "dnn_weights.h"

#include "nds_nn_softmax.h"
#include "nds_nn_activation.h"
#include "nds_nn_fully_connected.h"

#ifdef PF_COUNTER
#include "nds32_intrinsic.h"
#include "nds_pfcounter.h"
#endif

#include "test_util.h"

#define NUM_FRAMES        25
#define NUM_MFCC_COEFFS   10
#define IN_DIM            (NUM_FRAMES * NUM_MFCC_COEFFS)   /* 250 */
#define OUT_DIM           12
#define IP1_OUT_DIM       144
#define IP2_OUT_DIM       144
#define IP3_OUT_DIM       144
#define IP1_WT_DIM        (IP1_OUT_DIM * IN_DIM)
#define IP2_WT_DIM        (IP2_OUT_DIM * IP1_OUT_DIM)
#define IP3_WT_DIM        (IP3_OUT_DIM * IP2_OUT_DIM)
#define IP4_WT_DIM        (OUT_DIM * IP3_OUT_DIM)

static const q7_t ip1_wt[IP1_WT_DIM]   = IP1_WT;
static const q7_t ip1_bias[IP1_OUT_DIM]= IP1_BIAS;
static const q7_t ip2_wt[IP2_WT_DIM]   = IP2_WT;
static const q7_t ip2_bias[IP2_OUT_DIM]= IP2_BIAS;
static const q7_t ip3_wt[IP3_WT_DIM]   = IP3_WT;
static const q7_t ip3_bias[IP3_OUT_DIM]= IP3_BIAS;
static const q7_t ip4_wt[IP4_WT_DIM]   = IP4_WT;
static const q7_t ip4_bias[OUT_DIM]    = IP4_BIAS;

/* MFCC input (reproducible synthetic pattern; FC cycle cost is data-independent) */
static q7_t in_data[IN_DIM];
static q7_t ip1_out[IP1_OUT_DIM];
static q7_t ip2_out[IP2_OUT_DIM];
static q7_t ip3_out[IP3_OUT_DIM];
static q7_t out_data[OUT_DIM];
static q15_t vec_buffer[2 * IN_DIM];  /* 2 * max(in_dim) q15 scratch */

int main(void)
{
    enable_fs_and_vs();
    printf("start execution\n");

    int i;
    for (i = 0; i < IN_DIM; i++)
        in_data[i] = (q7_t)((i * 7) & 0x7f) - 64;

    /* enable un-aligned access (AX45MPV) */
    unsigned long reg;
    reg = __nds__mfsr(NDS_MMISC_CTL);
    reg |= (1 << 6);
    __nds__mtsr(reg, NDS_MMISC_CTL);

#if defined(PF_COUNTER)
    printf("Start ... \n");
    startPFM;
#endif

    /* IP1: 250 -> 144 */
#ifdef FUNCTION_PF_ANALYZE
    startPFM;
#endif
    riscv_nn_fc_s8_s8_s8_sft_bias_fast(in_data, ip1_wt, IN_DIM, IP1_OUT_DIM,
                                       1, 7, ip1_bias, ip1_out, vec_buffer);
#ifdef FUNCTION_PF_ANALYZE
    stopPFM;
    printf("IP1  riscv_nn_fc_s8_s8_s8_sft_bias_fast\tInst: %u, Cycle: %u\n", (unsigned)inst, (unsigned)cycle);
    startPFM;
#endif
    riscv_nn_relu_s8(ip1_out, IP1_OUT_DIM);
