/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// FullyConnected Functions
void riscv_nn_fc_s8_wt_converter(const q7_t *wt_mat,
                                const uint32_t size,
                                const uint32_t wt_row_num,
                                q7_t *wt_mat_out)
{
    long row, col;
    q7_t *ptr1 = (q7_t*)wt_mat,
         *ptr2 = ptr1 + size,
         *ptr3 = ptr2 + size,
         *ptr4 = ptr3 + size,
         *out = wt_mat_out;

    row = wt_row_num >> 2;
    while(row-- > 0)
    {
        col = size >> 2;
        while(col-- > 0)
        {
            *out++ = *ptr1;
            *out++ = *ptr2;
            *out++ = *(ptr1+2);
            *out++ = *(ptr2+2);

            *out++ = *ptr3;
            *out++ = *ptr4;
            *out++ = *(ptr3+2);
            *out++ = *(ptr4+2);

            *out++ = *(ptr1+1);
            *out++ = *(ptr2+1);
            *out++ = *(ptr1+3);
            *out++ = *(ptr2+3);

            *out++ = *(ptr3+1);
            *out++ = *(ptr4+1);
            *out++ = *(ptr3+3);
            *out++ = *(ptr4+3);

            ptr1 += 4;
            ptr2 += 4;
            ptr3 += 4;
            ptr4 += 4;
        }

        col = size & 3;
        while(col-- > 0)
        {
           *out++ = *ptr1++;
           *out++ = *ptr2++;
           *out++ = *ptr3++;
           *out++ = *ptr4++;
        }

        ptr1 += size * 3;
        ptr2 += size * 3;
        ptr3 += size * 3;
        ptr4 += size * 3;
    }

    row = wt_row_num & 3;
    long reset_length = row * size;
    memcpy(out, ptr1, reset_length * sizeof(*wt_mat));
}

