360	    uint32_t size2 = (size >> 2) << 2;
361	
362	#ifdef ENA_VEC_INTRINSIC
363	    //generate load index (swap the elements at index of 4n+1 and 4n+2)
364	    vl = __riscv_vsetvl_e8m1(size2);
365	    vuint8m1_t vIndex_u8 = __riscv_vid_v_u8m1(vl);
366	    vl = __riscv_vsetvl_e32m1(vl >> 2);
367	    vuint32m1_t vIndex_u32 = __riscv_vreinterpret_u32m1(vIndex_u8);
368	    //clear 4n+1 and 4n+2 index elements
369	    vuint32m1_t vtmp_a = __riscv_vand(vIndex_u32, 0xFF0000FF, vl);
370	    //select 4n+2 index elements
