int32_t riscv_nn_fc_s8_s8_s8_sft_bias_fast(const q7_t * in_vec,
                        const q7_t * wt_mat,
                        const uint16_t size,
                        const uint16_t wt_row_num,
                        const uint16_t bias_lshift,
                        const uint16_t out_rshift,
                        const q7_t * bias,
                        q7_t * out_vec,
                        q15_t * in_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC) && defined(ENA_VEC_INTRINSIC)
    const q7_t *pB = wt_mat;

