#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    const q7_t *pB = wt_mat;
    const q7_t *pBias = bias;
    q7_t *pO = out_vec;
    const q7_t *pA;
    int32_t vl;
    uint32_t rowCnt = wt_row_num >> 2;
    uint32_t colCnt = (size >> 2) << 4;

    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);

    //generate acc reduction mask
    //Note. each element only occupy 1 bit
    NDS_VEC_VSETVLI_E8(vl, (colCnt+7)>>3);
    NDS_VEC_VAND_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
    NDS_VEC_VOR_VX(NDS_VEC_V20, NDS_VEC_V0, 0x05);   //8n   8n+2 index mask (for acc1)
    NDS_VEC_VOR_VX(NDS_VEC_V21, NDS_VEC_V0, 0x0A);   //8n+1 8n+3 index mask (for acc2)
    NDS_VEC_VOR_VX(NDS_VEC_V22, NDS_VEC_V0, 0x50);   //8n+4 8n+6 index mask (for acc3)
    NDS_VEC_VOR_VX(NDS_VEC_V23, NDS_VEC_V0, 0xA0);   //8n+5 8n+7 index mask (for acc4)

    while (rowCnt)
    {
        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        uint32_t colCnt2 = colCnt;
        pA = (q7_t*)in_tmp_buf;
        /* init sum with bias */
        int32_t sum  = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
        int32_t sum2 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
        int32_t sum3 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
        int32_t sum4 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);

        //init
        NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
        NDS_VEC_VMV_S_X(NDS_VEC_V17, sum2);
        NDS_VEC_VMV_S_X(NDS_VEC_V18, sum3);
        NDS_VEC_VMV_S_X(NDS_VEC_V19, sum4);
        //clear v8~v15 (tmp acc)
        NDS_VEC_VAND_VX(NDS_VEC_V8, NDS_VEC_V8, 0);

        while(colCnt2)
        {
            NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VLB_V(NDS_VEC_V2, pA);
            NDS_VEC_VLB_V(NDS_VEC_V4, pB);
            NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
            colCnt2 -= vl;
            pA += vl;
            pB += vl;
        }

        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V20);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V16);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V21);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V8, NDS_VEC_V17);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V22);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8, NDS_VEC_V18);
        NDS_VEC_VMCPY_M(NDS_VEC_V0, NDS_VEC_V23);
        NDS_VEC_MSK_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V8, NDS_VEC_V19);

        //rest part
        NDS_VEC_VSETVLI_E32(vl, 4);     //4: 4 acc
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);

        NDS_VEC_VSETVLI_E8(vl, 4);     //4: 4 acc
        colCnt2 = size & 0x3;
        while(colCnt2)
        {
            q7_t inV = *pA++;
            NDS_VEC_VLB_V(NDS_VEC_V1, pB);
            NDS_VEC_VQMACC_VX(NDS_VEC_V16, inV, NDS_VEC_V1);
            pB += 4;
            colCnt2--;
        }

        NDS_VEC_VSETVLI_E32(vl, 4);     //4: 4 acc
        NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, out_rshift);
        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, Q7_MIN);
        NDS_VEC_VMIN_VX(NDS_VEC_V16, NDS_VEC_V16, Q7_MAX);

        NDS_VEC_VSETVLI_E16(vl, vl);
        NDS_VEC_VNSRA_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
        NDS_VEC_VSETVLI_E8(vl, vl);
        NDS_VEC_VNSRA_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
        NDS_VEC_VSB_V(NDS_VEC_V16, pO);
        pO += 4;
        rowCnt--;
    }

input.new_string:
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    const q7_t *pB = wt_mat;
    const q7_t *pBias = bias;
    q7_t *pO = out_vec;
    const q7_t *pA;
    int32_t vl;
    uint32_t rowCnt8 = wt_row_num >> 3;           // 8-row batched outers
    uint32_t rowCnt4 = (wt_row_num >> 2) & 1u;    // optional 4-row single group tail
    uint32_t colCnt = (size >> 2) << 4;
    const uint32_t wt_stride4 = (uint32_t)size * 4u; // bytes per 4-row converted block

    nn_dup_s8_x4_reordered(in_vec, (q7_t*)in_tmp_buf, size);

    //generate acc reduction mask
    //Note. each element only occupy 1 bit
    NDS_VEC_VSETVLI_E8(vl, (colCnt+7)>>3);
    NDS_VEC_VAND_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
    NDS_VEC_VOR_VX(NDS_VEC_V20, NDS_VEC_V0, 0x05);   //8n   8n+2 index mask (for acc1)
    NDS_VEC_VOR_VX(NDS_VEC_V21, NDS_VEC_V0, 0x0A);   //8n+1 8n+3 index mask (for acc2)
    NDS_VEC_VOR_VX(NDS_VEC_V22, NDS_VEC_V0, 0x50);   //8n+4 8n+6 index mask (for acc3)
    NDS_VEC_VOR_VX(NDS_VEC_V23, NDS_VEC_V0, 0xA0);   //8n+5 8n+7 index mask (for acc4)

    // 8-row batched outer: process 2 consecutive 4-row converted blocks per iter,
    // sharing the input load across both groups' inner VQMACC_VV.
    while (rowCnt8)
    {
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        /* init biases for both groups */
        int32_t sumA0 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
        int32_t sumA1 = ((q31_t)(*pBias++) << bias_lshift) + NN_ROUND(out_rshift);
